#!/usr/bin/env tsx
// session-start.ts — Inject brain context at session start
// Called from Claude Code SessionStart hook or pi session_start.
// Reads stdin JSON from hook, searches brain for relevant context,
// outputs context block to stdout (which becomes system prompt context).
//
// Usage: Called automatically by hook. No CLI arguments needed.

import { readFileSync } from "node:fs";
import { join } from "node:path";
import { BrainStore } from "./store.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

const MAX_CONTEXT_CHARS = 4000;

interface SessionStartInput {
  session_id?: string;
  cwd?: string;
  hook_event_name?: string;
}

function readInput(): SessionStartInput {
  try {
    const stdin = readFileSync(0, "utf-8").trim();
    if (stdin) return JSON.parse(stdin);
  } catch {
    // no stdin
  }
  return {};
}

function getCwdPrompt(): string {
  // Try to extract a project name from cwd
  try {
    const input = readInput();
    if (input.cwd) {
      const parts = input.cwd.split("/").filter(Boolean);
      const skip = new Set(["Users", "home", "nbr", "repos", "nikbrunner", "workplace"]);
      const relevant = parts.filter(p => !skip.has(p));
      return relevant.join(" ");
    }
  } catch {
    // ignore
  }
  return "";
}

async function buildContext(): Promise<string> {
  const store = new BrainStore(DB_PATH);
  const sections: string[] = [];

  // 1. Penny's self-model (always injected)
  const selfFiles = store.searchByType("penny", "self", 1);
  if (selfFiles.length > 0) {
    sections.push(`## My Self-Model\n${selfFiles[0].excerpt}`);
  }

  // 2. People context (key facts about Nik — always injected)
  const peopleFiles = store.searchByType("nik", "person", 2);
  if (peopleFiles.length > 0) {
    const facts = peopleFiles.map(f => f.excerpt).join("\n");
    sections.push(`## About Nik\n${facts.slice(0, 800)}`);
  }

  // 3. Project context (from cwd)
  const cwdPrompt = getCwdPrompt();
  if (cwdPrompt) {
    const projectResults = store.search(cwdPrompt, 3);
    if (projectResults.length > 0) {
      const projectContext = projectResults.map(r => `- [${r.type}] ${r.excerpt}`).join("\n");
      sections.push(`## Project Context\n${projectContext}`);
    }
  }

  // 4. Recent patterns (last updated)
  const patterns = store.searchByTag("patterns", 5);
  if (patterns.length > 0) {
    const patternContext = patterns.slice(0, 3).map(r => `- ${r.excerpt.slice(0, 150)}`).join("\n");
    sections.push(`## Patterns\n${patternContext}`);
  }

  // 5. Recent sessions (last 7 days)
  const sessions = store.searchByType("sessions", "sessions", 3);
  if (sessions.length > 0) {
    const sessionContext = sessions.map(r => `- ${r.title}: ${r.excerpt.slice(0, 100)}`).join("\n");
    sections.push(`## Recent Sessions\n${sessionContext}`);
  }

  // 6. Important lessons (corrections to remember)
  const corrections = store.searchByTag("correction", 5);
  if (corrections.length > 0) {
    const correctionContext = corrections.map(r => `- ${r.excerpt.slice(0, 150)}`).join("\n");
    sections.push(`## Before Acting\n${correctionContext}`);
  }

  store.close();

  if (sections.length === 0) return "";

  let text = `<penny_brain>\n${sections.join("\n\n")}\n\n## Reminder\n- Memory records can become stale. Verify before relying on them.\n- If memory conflicts with what you observe, trust observation.\n</penny_brain>`;

  if (text.length > MAX_CONTEXT_CHARS) {
    text = text.slice(0, MAX_CONTEXT_CHARS - 20) + "\n... (truncated)\n</penny_brain>";
  }

  return text;
}

async function main(): Promise<void> {
  const context = await buildContext();
  if (context) {
    // Output in Claude Code hook format: JSON with additionalContext
    // Plain text also works for SessionStart (Claude injects stdout as context)
    // but JSON format is more explicit and reliable.
    const escaped = context.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
    console.log(JSON.stringify({
      hookSpecificOutput: {
        hookEventName: "SessionStart",
        additionalContext: escaped,
      },
    }));
  }
}

main().catch(err => {
  console.error("session-start failed:", err);
  process.exit(1);
});

/**
 * third-brain Pi extension — Penny's long-term memory
 *
 * Hooks into pi lifecycle to:
 * - Inject brain context at session start
 * - Collect messages for consolidation
 * - Provide memory tools (remember, recall, forget, stats)
 *
 * Logging: uses status bar (setStatus), notifications (notify),
 * and console.error (debug log) for visibility at every lifecycle point.
 */

import type { ExtensionAPI, AgentToolResult } from "@earendil-works/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { join } from "node:path";
import { homedir } from "node:os";
import { execFileSync } from "node:child_process";

type ToolResult = AgentToolResult<unknown>;
function ok(text: string): ToolResult {
  return { content: [{ type: "text", text }], details: {} };
}

const HOME = homedir();
const THIRD_BRAIN_DIR = join(HOME, "repos", "nikbrunner", "third-brain");
const SCRIPTS_DIR = join(THIRD_BRAIN_DIR, "scripts");
const TSX = join(THIRD_BRAIN_DIR, "node_modules", ".bin", "tsx");

interface RunResult {
  stdout: string;
  stderr: string;
  ok: boolean;
}

function runScript(script: string, ...args: string[]): RunResult {
  try {
    const result = execFileSync(TSX, [join(SCRIPTS_DIR, script), ...args], {
      encoding: "utf8",
      timeout: 15_000,
      maxBuffer: 1024 * 1024,
      cwd: THIRD_BRAIN_DIR,
      stdio: ["pipe", "pipe", "pipe"],
    });
    // For execFileSync with stdio pipe, result is the stdout string directly
    return { stdout: (result || "").trim(), stderr: "", ok: true };
  } catch (err: unknown) {
    const e = err as { stdout?: string; stderr?: string; message?: string; code?: string };
    if (e.code === "ETIMEDOUT") {
      return { stdout: "", stderr: `${script}: timed out`, ok: false };
    }
    return { stdout: e.stdout || "", stderr: e.stderr || e.message || "Unknown error", ok: false };
  }
}

function runScriptWithInput(script: string, input: string, ...args: string[]): RunResult {
  try {
    const result = execFileSync(TSX, [join(SCRIPTS_DIR, script), ...args], {
      encoding: "utf8",
      timeout: 45_000,
      maxBuffer: 1024 * 1024,
      cwd: THIRD_BRAIN_DIR,
      input,
      stdio: ["pipe", "pipe", "pipe"],
    });
    // For execFileSync with stdio pipe, result is the stdout string directly
    return { stdout: (result || "").trim(), stderr: "", ok: true };
  } catch (err: unknown) {
    const e = err as { stdout?: string; stderr?: string; message?: string; code?: string };
    if (e.code === "ETIMEDOUT") {
      return { stdout: "", stderr: `${script}: timed out`, ok: false };
    }
    return { stdout: e.stdout || "", stderr: e.stderr || e.message || "Unknown error", ok: false };
  }
}

/** Parse "Index: 75 files" → 75 */
function parseFileCount(stdout: string): number {
  const m = stdout.match(/Index:\s+(\d+)\s+files/);
  return m ? parseInt(m[1], 10) : 0;
}

/** Parse "Extracted X memories" → X */
function parseExtractedCount(stdout: string): number {
  const m = stdout.match(/Extracted\s+(\d+)\s+memor/);
  return m ? parseInt(m[1], 10) : 0;
}

/** Count result entries from recall output */
function countRecallResults(stdout: string): number {
  return (stdout.match(/^\[/gm) || []).length;
}

function extractText(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content
      .filter((c: any) => c.type === "text" && typeof c.text === "string")
      .map((c: any) => c.text)
      .join("\n");
  }
  return "";
}

export default function (pi: ExtensionAPI) {
  let pendingUserMessages: string[] = [];
  let pendingAssistantMessages: string[] = [];
  let sessionMsgCount = 0;

  // ─── Lifecycle ──────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    const startTime = Date.now();

    const stats = runScript("sync-index.ts");
    const fileCount = parseFileCount(stats.stdout);

    if (stats.ok && fileCount > 0) {
      const elapsed = Date.now() - startTime;
      console.error(`[third-brain] ✅ Loaded: ${fileCount} files indexed (${elapsed}ms)`);
      ctx.ui.notify(`🧠 Third-brain: ${fileCount} memories loaded`, "info");
      ctx.ui.setStatus("third-brain", `🧠 ${fileCount} mem`);
    } else if (!stats.ok) {
      console.error(`[third-brain] ⚠️ Index unavailable: ${stats.stderr}`);
      ctx.ui.notify(`⚠️ Third-brain offline: ${stats.stderr}`, "error");
      ctx.ui.setStatus("third-brain", `🧠 ⚠️ offline`);
    } else {
      console.error(`[third-brain] ⚠️ Empty (0 files). Run bootstrap?`);
      ctx.ui.notify("🧠 Third-brain empty — run bootstrap first", "error");
      ctx.ui.setStatus("third-brain", `🧠 empty`);
    }
  });

  pi.on("before_agent_start", async (event, ctx) => {
    const prompt = event.prompt;
    ctx.ui.setStatus("third-brain", "🔍 Searching...");

    try {
      const result = execFileSync(TSX, [
        join(SCRIPTS_DIR, "recall.ts"),
        prompt,
        "--limit", "5",
      ], {
        encoding: "utf8",
        timeout: 10_000,
        maxBuffer: 256 * 1024,
        cwd: THIRD_BRAIN_DIR,
        stdio: ["pipe", "pipe", "pipe"],
      });

      const stdout = (result || "").trim();
      const found = countRecallResults(stdout);

      if (found > 0) {
        console.error(`[third-brain] Injected ${found} relevant memories for: "${prompt.slice(0, 80)}..."`);
        ctx.ui.notify(`🧠 Injected ${found} relevant memories into context`, "info");
        ctx.ui.setStatus("third-brain", `🧠 +${found} ctx`);

        return {
          systemPrompt: `${event.systemPrompt}\n\n<memory>\nRelevant memories from Penny's brain:\n${stdout}\n</memory>`,
        };
      } else {
        ctx.ui.setStatus("third-brain", `🧠 idle`);
      }
    } catch {
      console.error(`[third-brain] ⚠️ Search failed for prompt`);
      ctx.ui.setStatus("third-brain", `🧠 idle`);
    }
  });

  pi.on("agent_end", async (event, _ctx) => {
    sessionMsgCount++;
    for (const msg of event.messages) {
      if (msg.role === "user" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingUserMessages.push(text);
          if (pendingUserMessages.length > 60) pendingUserMessages.shift();
        }
      } else if (msg.role === "assistant" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingAssistantMessages.push(text);
          if (pendingAssistantMessages.length > 60) pendingAssistantMessages.shift();
        }
      }
    }
  });

  pi.on("session_before_switch", async (_event, ctx) => {
    if (pendingUserMessages.length >= 3) {
      console.error(`[third-brain] Consolidating ${pendingUserMessages.length} turns...`);
      ctx.ui.setStatus("third-brain", "🧠 Consolidating...");

      try {
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        const result = runScriptWithInput("consolidate.ts", JSON.stringify(messages));
        const extracted = parseExtractedCount(result.stdout);

        if (result.ok && extracted > 0) {
          console.error(`[third-brain] ✅ Consolidated: ${extracted} new memories`);
          ctx.ui.notify(`🧠 Consolidated ${extracted} new memories from conversation`, "success");
          ctx.ui.setStatus("third-brain", `🧠 +${extracted} saved`);
        } else if (result.ok) {
          console.error(`[third-brain] Consolidation ran — nothing new`);
          ctx.ui.setStatus("third-brain", `🧠 idle`);
        } else {
          console.error(`[third-brain] ⚠️ Consolidation failed: ${result.stderr}`);
          ctx.ui.notify(`⚠️ Brain consolidation failed: ${result.stderr}`, "error");
          ctx.ui.setStatus("third-brain", `🧠 ⚠️ error`);
        }
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error(`[third-brain] ⚠️ Consolidation error: ${msg}`);
        ctx.ui.notify(`⚠️ Brain consolidation error: ${msg}`, "error");
        ctx.ui.setStatus("third-brain", `🧠 ⚠️ error`);
      }

      pendingUserMessages = [];
      pendingAssistantMessages = [];
    }
  });

  pi.on("session_shutdown", async () => {
    if (pendingUserMessages.length >= 3) {
      console.error(`[third-brain] Shutdown: consolidating ${pendingUserMessages.length} turns...`);
      try {
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        const result = runScriptWithInput("consolidate.ts", JSON.stringify(messages));
        const extracted = parseExtractedCount(result.stdout);
        if (result.ok && extracted > 0) {
          console.error(`[third-brain] ✅ Shutdown consolidated: ${extracted} memories`);
        }
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error(`[third-brain] ⚠️ Shutdown consolidation: ${msg}`);
      }
    }
    console.error(`[third-brain] Session ended (${sessionMsgCount} agent turns)`);
  });

  // ─── Tools ──────────────────────────────────────────────────────────

  pi.registerTool({
    name: "brain_remember",
    label: "Brain Remember",
    description: "Write a memory to Penny's third-brain. Use for decisions, corrections, personal facts, or project insights worth keeping across sessions.",
    parameters: Type.Object({
      content: Type.String({ description: "The fact, decision, or observation to remember (one sentence)" }),
      type: Type.Optional(Type.String({ description: "Memory type: person, projects, patterns, sessions, self, or daily (default)" })),
      tags: Type.Optional(Type.String({ description: "Comma-separated tags for categorization" })),
      project: Type.Optional(Type.String({ description: "Project name (for type=projects, e.g. 'dots', 'third-brain')" })),
      org: Type.Optional(Type.String({ description: "Org/owner (for type=projects, default 'nikbrunner')" })),
    }) as any,
    async execute(_id, params, _signal, _update, ctx) {
      const type = params.type || "daily";
      const tags = params.tags || "";

      const args = [
        "--content", params.content,
        "--type", type,
        "--tags", tags,
        "--commit",
      ];
      if (params.project) {
        args.push("--project", params.project);
        args.push("--org", params.org || "nikbrunner");
      }

      const result = runScript("remember.ts", ...args);

      if (result.ok) {
        console.error(`[third-brain] ✅ Remembered [${type}]: ${params.content.slice(0, 80)}`);
        ctx.ui.notify(`🧠 Saved memory [${type}]: ${params.content.slice(0, 60)}`, "success");
        return ok(result.stdout || `🧠 Remembered [${type}]: ${params.content}`);
      } else {
        console.error(`[third-brain] ⚠️ remember failed: ${result.stderr}`);
        ctx.ui.notify(`⚠️ Failed to save memory: ${result.stderr}`, "error");
        return ok(`⚠️ Failed to remember: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_recall",
    label: "Brain Recall",
    description: "Search Penny's third-brain for relevant memories, facts, or context.",
    parameters: Type.Object({
      query: Type.String({ description: "Search query" }),
      type: Type.Optional(Type.String({ description: "Filter by type: person, projects, patterns, sessions, self" })),
      limit: Type.Optional(Type.Number({ description: "Max results (default 5)" })),
    }) as any,
    async execute(_id, params, _signal, _update, ctx) {
      const limit = params.limit || 5;
      const args = [params.query, "--limit", String(limit)];
      if (params.type) args.push("--type", params.type);

      const result = runScript("recall.ts", ...args);
      const found = countRecallResults(result.stdout);

      console.error(`[third-brain] Recall "${params.query.slice(0, 60)}" → ${found} results`);

      if (result.ok && found > 0) {
        ctx.ui.notify(`🧠 Recall: found ${found} for "${params.query.slice(0, 40)}"`, "info");
        return ok(`🧠 Found ${found} memories:\n\n${result.stdout}`);
      } else if (result.ok) {
        return ok("🧠 No matching memories found.");
      } else {
        ctx.ui.notify(`⚠️ Recall failed: ${result.stderr}`, "error");
        return ok(`⚠️ Recall failed: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_forget",
    label: "Brain Forget",
    description: "Remove a memory from Penny's third-brain.",
    parameters: Type.Object({
      file: Type.String({ description: "Brain file path (e.g., person/nik.md)" }),
      match: Type.String({ description: "Text to match for removal" }),
      section: Type.Optional(Type.String({ description: "Section heading to search within" })),
    }) as any,
    async execute(_id, params, _signal, _update, ctx) {
      const args = ["--file", params.file, "--match", params.match];
      if (params.section) args.push("--section", params.section);

      const result = runScript("forget.ts", ...args);

      if (result.ok) {
        console.error(`[third-brain] 🗑️ Forgotten from ${params.file}: "${params.match.slice(0, 60)}"`);
        ctx.ui.notify(`🧹 Forgotten: "${params.match.slice(0, 40)}"`, "info");
        return ok(result.stdout || `🗑️ Removed "${params.match}" from ${params.file}`);
      } else {
        console.error(`[third-brain] ⚠️ forget failed: ${result.stderr}`);
        ctx.ui.notify(`⚠️ Forget failed: ${result.stderr}`, "error");
        return ok(`⚠️ Forget failed: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_stats",
    label: "Brain Stats",
    description: "Show third-brain statistics — file counts by type, index status.",
    parameters: Type.Object({}) as any,
    async execute(_id, _params, _signal, _update, ctx) {
      const result = runScript("sync-index.ts");
      const fileCount = parseFileCount(result.stdout);

      console.error(`[third-brain] Stats: ${fileCount} files`);

      if (result.ok && fileCount > 0) {
        ctx.ui.notify(`🧠 Third-brain: ${fileCount} memories`, "info");
        return ok(`🧠 Third-brain stats:\n\n${result.stdout}`);
      } else if (result.ok) {
        return ok("🧠 Brain is empty. Run bootstrap to seed initial knowledge.");
      } else {
        ctx.ui.notify(`⚠️ Stats unavailable: ${result.stderr}`, "error");
        return ok(`⚠️ Stats unavailable: ${result.stderr}`);
      }
    },
  });
}

#!/usr/bin/env tsx
// recall.ts — Search the third-brain
// Usage: tsx scripts/recall.ts "what does Nik prefer for scripting"
//        tsx scripts/recall.ts --type person --tag nik
//        tsx scripts/recall.ts --limit 5 "job search"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import type { SearchResult } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RecallArgs {
  query: string;
  type?: string;
  tag?: string;
  limit: number;
}

function parseCliArgs(): RecallArgs {
  const { values, positionals } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string" },
      tag: { type: "string" },
      limit: { type: "string", default: "10" },
    },
    allowPositionals: true,
  });

  return {
    query: positionals.join(" ") || "",
    type: values.type as string | undefined,
    tag: values.tag as string | undefined,
    limit: parseInt(values.limit as string, 10) || 10,
  };
}

async function recall(args: RecallArgs): Promise<SearchResult[]> {
  const store = new BrainStore(DB_PATH);

  let results: SearchResult[];

  if (args.tag) {
    results = store.searchByTag(args.tag, args.limit);
  } else if (args.type && args.query) {
    results = store.searchByType(args.query, args.type, args.limit);
  } else if (args.type) {
    // List all of a type
    results = store.listFiles(args.type).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  } else if (args.query) {
    results = store.search(args.query, args.limit);
  } else {
    // No filter — list recent
    results = store.listFiles().slice(0, args.limit).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  store.close();
  return results;
}

function formatResults(results: SearchResult[]): string {
  if (results.length === 0) return "No memories found.";

  const lines: string[] = [];
  for (const r of results) {
    lines.push(`[${r.type}] ${r.title} (${r.file})`);
    lines.push(`  ${r.excerpt.replace(/\n/g, " ").slice(0, 150)}`);
    if (r.tags.length > 0) lines.push(`  tags: ${r.tags.join(", ")}`);
    lines.push("");
  }
  return lines.join("\n");
}

// Allow programmatic use
export async function recallMemory(
  query: string,
  options?: { type?: string; tag?: string; limit?: number }
): Promise<SearchResult[]> {
  return recall({
    query,
    type: options?.type,
    tag: options?.tag,
    limit: options?.limit || 10,
  });
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/recall.ts")) {
  const args = parseCliArgs();
  recall(args).then(results => {
    console.log(formatResults(results));
  }).catch(err => {
    console.error("recall failed:", err);
    process.exit(1);
  });
}

// SQLite store for the third-brain index
// Wraps Node's built-in node:sqlite — FTS5 search on markdown content

import { DatabaseSync } from "node:sqlite";
import { mkdirSync, existsSync } from "node:fs";
import { dirname } from "node:path";
import type { IndexedFile, SearchResult } from "./types.js";

export class BrainStore {
  private db: DatabaseSync;
  private hasFTS5 = false;

  constructor(dbPath: string) {
    const dir = dirname(dbPath);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

    this.db = new DatabaseSync(dbPath);
    this.db.exec("PRAGMA journal_mode = WAL");
    this.db.exec("PRAGMA busy_timeout = 5000");
    this.migrate();
  }

  private migrate(): void {
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS files (
        path TEXT PRIMARY KEY,
        checksum TEXT NOT NULL,
        type TEXT NOT NULL,
        tags TEXT NOT NULL DEFAULT '',
        title TEXT NOT NULL DEFAULT '',
        content TEXT NOT NULL DEFAULT '',
        updated TEXT NOT NULL DEFAULT '',
        indexed_at TEXT NOT NULL DEFAULT (datetime('now'))
      );
    `);

    // Try FTS5 — fall back to substring if unavailable
    try {
      this.db.exec(`
        CREATE VIRTUAL TABLE IF NOT EXISTS files_fts USING fts5(
          path, title, content, tags,
          content='files', content_rowid='rowid'
        );

        CREATE TRIGGER IF NOT EXISTS files_ai AFTER INSERT ON files BEGIN
          INSERT INTO files_fts(rowid, path, title, content, tags)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_ad AFTER DELETE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_au AFTER UPDATE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
          INSERT INTO files_fts(rowid, path, title, content, tags)
