  // ─── File operations ──────────────────────────────────────────────

  upsertFile(file: IndexedFile): void {
    this.db.prepare(`
      INSERT INTO files (path, checksum, type, tags, title, content, updated, indexed_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, datetime('now'))
      ON CONFLICT(path) DO UPDATE SET
        checksum = excluded.checksum,
        type = excluded.type,
        tags = excluded.tags,
        title = excluded.title,
        content = excluded.content,
        updated = excluded.updated,
        indexed_at = datetime('now')
    `).run(
      file.path || "",
      file.checksum || "",
      file.type || "unknown",
      file.tags || "",
      file.title || "",
      file.content || "",
      file.updated || ""
    );
  }

  getFile(path: string): IndexedFile | undefined {
    return this.db.prepare("SELECT * FROM files WHERE path = ?").get(path) as IndexedFile | undefined;
  }

  deleteFile(path: string): boolean {
    const result = this.db.prepare("DELETE FROM files WHERE path = ?").run(path);
    return result.changes > 0;
  }

  listFiles(type?: string): IndexedFile[] {

