#!/usr/bin/env tsx
/**
 * migrate-slugs.ts — Phase 2 migration
 *
 * Renames brain files to clean human-readable slugs, adds `title` and `domain`
 * fields to frontmatter.
 *
 * Usage: tsx scripts/migrate-slugs.ts              # preview only
 *        tsx scripts/migrate-slugs.ts --apply       # apply changes
 *        tsx scripts/migrate-slugs.ts --apply --domain personal  # override default domain
 */

import { readFileSync, writeFileSync, renameSync, existsSync, mkdirSync } from "node:fs";
import { readdir, stat } from "node:fs/promises";
import { join, dirname, relative, basename } from "node:path";
import { createHash } from "node:crypto";
import matter from "gray-matter";
import type { BrainFileFrontmatter, DomainType } from "./types.js";

const BRAIN_DIR = join(import.meta.dirname, "..", "brain");

// ─── Slug generation ──────────────────────────────────────────────────

const COMMON_WORDS = new Set([
  "the", "a", "an", "and", "or", "but", "in", "on", "at", "to", "for",
  "of", "with", "by", "from", "as", "is", "are", "was", "were", "be",
  "been", "being", "have", "has", "had", "do", "does", "did", "will",
  "would", "could", "should", "may", "might", "shall", "can", "need",
  "its", "it's", "not", "no", "nor", "so", "if", "then", "than", "that",
  "this", "these", "those", "which", "who", "whom", "what", "when",
  "where", "why", "how", "all", "each", "every", "both", "few", "more",
  "most", "other", "some", "such", "only", "own", "same", "too", "very",
  "just", "also", "about", "above", "after", "again", "against", "below",
  "between", "during", "before", "behind", "under", "over", "out", "up",
  "into", "through", "along", "around", "among", "across", "without",
  "within", "upon", "onto", "off", "down", "away", "back", "here",
  "there", "where", "everywhere", "always", "never", "sometimes",
  "often", "usually", "rarely", "already", "still", "yet", "even",
]);

function slugify(text: string): string {
  // Remove emojis, special chars
  let s = text
    .replace(/[^\w\s-]/g, "")    // remove punctuation, emojis
    .replace(/[–—]/g, "-")       // dashes to hyphen
    .trim()
    .toLowerCase();

  // Split into words, filter out common words and short words, keep max 8
  const words = s.split(/\s+/).filter(Boolean);
  const meaningful = words.filter(w => w.length > 2 && !COMMON_WORDS.has(w));
  const keep = meaningful.length >= 3 ? meaningful : words; // if not enough meaningful words, keep all
  const slug = keep.slice(0, 8).join("-");

  // Remove trailing dashes
  return slug.replace(/-+$/, "");
}

// ─── File scanning ────────────────────────────────────────────────────

interface MigrationEntry {
  oldRelativePath: string;
  newRelativePath: string;
  type: string;
  title: string;
  currentTags: string[];
  proposedDomain: DomainType;
  isCodingCandidate: boolean;
}

async function scanBrainFiles(): Promise<MigrationEntry[]> {
  const entries: MigrationEntry[] = [];

  async function scanDir(dir: string): Promise<void> {
    if (!existsSync(dir)) return;
    const items = await readdir(dir, { withFileTypes: true });
    for (const item of items) {
      const fullPath = join(dir, item.name);
      if (item.isDirectory()) {
        if (item.name.startsWith("_") || item.name === "templates") continue;
        await scanDir(fullPath);
      } else if (item.isFile() && item.name.endsWith(".md")) {
        const relPath = relative(BRAIN_DIR, fullPath);
        const raw = readFileSync(fullPath, "utf-8");
        const parsed = matter(raw);
        const fm = (parsed.data || {}) as BrainFileFrontmatter;
        const type = fm.type || deduceTypeFromPath(relPath);
        const content = parsed.content;
        const title = fm.title || extractTitleFromContent(content) || titleFromFilename(item.name);

        // Generate new slug
        const slug = slugify(title);
        const parentDir = dirname(relPath);
        const newRelPath = parentDir === "." ? `${slug}.md` : `${parentDir}/${slug}.md`;

        // Detect coding candidate
        const isCoding = isCodingCandidate(relPath, type, title, fm.tags || []);

        entries.push({
          oldRelativePath: relPath,
          newRelativePath: newRelPath,
          type,
          title,
          currentTags: fm.tags || [],
          proposedDomain: isCoding ? "coding" : "personal",
          isCodingCandidate: isCoding,
        });
      }
    }
  }

  await scanDir(BRAIN_DIR);
  return entries;
}

function deduceTypeFromPath(relPath: string): string {
  const dir = dirname(relPath);
  if (dir === "person") return "person";
  if (dir === "patterns") return "patterns";
  if (dir === "projects" || dir.startsWith("projects/")) return "projects";
  if (dir === "self") return "self";
  if (dir === "sessions") return "sessions";
  if (dir === "daily") return "daily";
  return "unknown";
}

function extractTitleFromContent(content: string): string | null {
  const match = content.match(/^#\s+(.+)$/m);
  return match ? match[1].trim() : null;
}

function titleFromFilename(filename: string): string {
  return filename.replace(/\.md$/, "").replace(/[-_]/g, " ");
}

const CODING_FILENAME_MARKERS = [
  "react", "css-modules", "typescript", "tanstack", "tdd",
  "dev-flow", "commit", "conventional-commit", "editor-neovim",
  "code-intelligence", "tool-keyboard", "tools-github", "primary-stack",
  "skill-first-task", "skill-that-overlap", "research-first",
  "coding-style", "dotfiles", "fixed-neovim", "state-separate",
  "don-t-echo", "don-t-put-project", "also-experienced",
  "created-brain-learn", "renamed-4-crud", "restructured-brain",
];

const CODING_TITLE_MARKERS = [
  "react", "typescript", "css", "tanstack", "tdd", "commit",
  "editor", "neovim", "code intelligence", "tooling", "github cli",
  "skill dispatch", "research", "coding style", "dotfiles",
  "state separation", "testing", "git workflow",
];

function isCodingCandidate(path: string, type: string, title: string, tags: string[]): boolean {
  if (type === "projects") return true;
  if (type === "daily" || type === "sessions") return false;

  const lowerPath = path.toLowerCase();
  const lowerTitle = title.toLowerCase();
  const lowerTags = tags.map(t => t.toLowerCase());

  // Check filename markers
  for (const marker of CODING_FILENAME_MARKERS) {
    if (lowerPath.includes(marker)) return true;
  }

  // Check title markers
  for (const marker of CODING_TITLE_MARKERS) {
    if (lowerTitle.includes(marker)) return true;
  }

  // Check tags
  const codingTags = ["technical", "typescript", "react", "css", "tdd", "git", "tooling", "dev"];
  for (const tag of codingTags) {
    if (lowerTags.includes(tag)) return true;
  }

  return false;
}

// ─── Preview ──────────────────────────────────────────────────────────

function formatPreview(entries: MigrationEntry[]): string {
  const lines: string[] = [];
  let renamed = 0;
  let codingCount = 0;

  // Group by type
  const byType = new Map<string, MigrationEntry[]>();
  for (const e of entries) {
    const key = e.type;
    if (!byType.has(key)) byType.set(key, []);
    byType.get(key)!.push(e);
  }

  for (const [type, group] of byType) {
    lines.push(`\n## ${type} (${group.length})`);
    for (const e of group) {
      const renamedFlag = e.oldRelativePath !== e.newRelativePath ? " 🔄" : "";
      if (renamedFlag) renamed++;
      const codingTag = e.proposedDomain === "coding" ? " [CODING]" : "";
      if (e.proposedDomain === "coding") codingCount++;
      lines.push(`  ${e.oldRelativePath}`);
      lines.push(`  → ${e.newRelativePath}${renamedFlag}${codingTag}`);
      lines.push(`    Title: ${e.title}`);
      lines.push("");
    }
  }

  lines.unshift(`\nSummary: ${entries.length} files total`);
  lines.unshift(`  Renamed: ${renamed} files`);
  lines.unshift(`  Coding domain: ${codingCount} files`);
  lines.unshift(`  Personal domain: ${entries.length - codingCount} files`);

  return lines.join("\n");
}

// ─── Apply migration ──────────────────────────────────────────────────

function applyMigration(entries: MigrationEntry[], defaultDomain: DomainType): void {
  let renamed = 0;
  let updated = 0;

  for (const e of entries) {
    const oldPath = join(BRAIN_DIR, e.oldRelativePath);
    const newPath = join(BRAIN_DIR, e.newRelativePath);

    if (!existsSync(oldPath)) {
      console.error(`  [SKIP] Not found: ${e.oldRelativePath}`);
      continue;
    }

    // Read and update frontmatter
    const raw = readFileSync(oldPath, "utf-8");
    const parsed = matter(raw);

    // Preserve existing fields, add/update title and domain
    const fm = (parsed.data || {}) as Record<string, unknown>;
    fm.title = e.title;

    // Only set domain if not already present
    if (!fm.domain) {
      fm.domain = e.proposedDomain;
    }

    const newRaw = matter.stringify(parsed.content, fm);

    // Check if path changed
    if (e.oldRelativePath !== e.newRelativePath) {
      // Ensure target directory exists
      const targetDir = dirname(newPath);
      if (!existsSync(targetDir)) mkdirSync(targetDir, { recursive: true });

      // Write new file
      writeFileSync(newPath, newRaw, "utf-8");

      // Remove old file
      const oldDir = dirname(oldPath);
      renameSync(oldPath, newPath); // atomic rename — works on same filesystem
      renamed++;
      console.log(`  [RENAME] ${e.oldRelativePath} → ${e.newRelativePath}`);
    } else {
      // Same path, just update frontmatter
      writeFileSync(oldPath, newRaw, "utf-8");
      updated++;
      console.log(`  [UPDATE] ${e.oldRelativePath} (title + domain added)`);
    }
  }

  console.log(`\nDone: ${renamed} renamed, ${updated} frontmatter-updated`);
}

// ─── Main ─────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const args = process.argv.slice(2);
  const apply = args.includes("--apply");
  const defaultDomain = (args.find(a => a.startsWith("--domain="))?.split("=")[1] || "personal") as DomainType;
  const skipProjects = args.includes("--skip-projects");

  console.log("Scanning brain files...\n");

  const entries = await scanBrainFiles();
  let filtered = entries;
  if (skipProjects) {
    filtered = entries.filter(e => e.type !== "projects");
  }

  const preview = formatPreview(filtered);
  console.log(preview);

  if (!apply) {
    console.log("\n---");
    console.log("This is a preview. Run with --apply to execute.");
    console.log("Use --domain=coding to override default domain (default: personal).");
    console.log("Use --skip-projects to leave project files untouched.");
    process.exit(0);
  }

  console.log("\nApplying migration...\n");
  applyMigration(filtered, defaultDomain);
}

main().catch(err => {
  console.error("Migration failed:", err);
  process.exit(1);
});

