const BRAIN_DIR = join(import.meta.dirname, "..", "brain");

// ─── Helpers ──────────────────────────────────────────────────────────

function extractTitle(content: string): string | null {
  // H1 heading
  const h1 = content.match(/^#\s+(.+)$/m);
  if (h1) return h1[1].trim();

  // First bullet point under ## Key Facts
  const keyFactsMatch = content.match(/^##\s+Key Facts\s*\n+\s*-\s+(.+)$/m);
  if (keyFactsMatch) {
    let bullet = keyFactsMatch[1].trim();
    // If bullet has colon, take the part before it as a label
    const colonIdx = bullet.indexOf(":");
    if (colonIdx > 0 && colonIdx < 60) {
      bullet = bullet.slice(0, colonIdx).trim();
    }
    return bullet;
  }

  return null;
}

function slugify(text: string): string {
  let s = text
    .replace(/[''']/g, "")       // smart apostrophes → nothing
    .replace(/[–—]/g, "-")       // dashes to hyphen
    .replace(/[^\w\s-]/g, "")    // remove punctuation, emojis
    .trim()
    .toLowerCase();

  const words = s.split(/\s+/).filter(w => w.length > 0);
  const meaningful = words.filter(w => w.length > 2);
  const keep = meaningful.length >= 2 ? meaningful : words;
  return keep.slice(0, 7).join("-").replace(/-+$/, "");
}

function cleanHumanTitle(raw: string): string {
  return raw
    .replace(/[''']/g, "'")      // normalize apostrophes
