function extractTitle(content: string): string | null {
  // H1 heading
  const h1 = content.match(/^#\s+(.+)$/m);
  if (h1) return h1[1].trim();

  // Any ## section heading — take the first non-blank line after it
  const sections = content.match(/^##\s+(.+)$/gm);
  if (sections && sections.length > 0) {
    // Read the first line after the heading that starts with "- "
    const lines = content.split("\n");
    for (let i = 0; i < lines.length; i++) {
      if (lines[i].startsWith("## ")) {
        // Look ahead for next heading or first bullet
        for (let j = i + 1; j < Math.min(i + 10, lines.length); j++) {
          const line = lines[j].trim();
          if (line.startsWith("- ") || line.startsWith("* ")) {
            let bullet = line.replace(/^[-*]\s+/, "");
            // If bullet has colon, take the part before as label
            const colonIdx = bullet.indexOf(":");
            if (colonIdx > 0 && colonIdx < 60) {
              bullet = bullet.slice(0, colonIdx).trim();
            }
            return bullet;
          }
          if (line.startsWith("#")) break;
        }
      }
    }
  }

  return null;
}

