// SQLite store for the third-brain index
// Wraps Node's built-in node:sqlite — FTS5 search on markdown content

import { DatabaseSync } from "node:sqlite";
import { mkdirSync, existsSync } from "node:fs";
import { dirname } from "node:path";
import type { IndexedFile, SearchResult } from "./types.js";

export class BrainStore {
  private db: DatabaseSync;
  private hasFTS5 = false;

  constructor(dbPath: string) {
    const dir = dirname(dbPath);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

    this.db = new DatabaseSync(dbPath);
    this.db.exec("PRAGMA journal_mode = WAL");
    this.db.exec("PRAGMA busy_timeout = 5000");
    this.migrate();
  }

  private migrate(): void {
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS files (
        path TEXT PRIMARY KEY,
        checksum TEXT NOT NULL,
        type TEXT NOT NULL,
        tags TEXT NOT NULL DEFAULT '',
        title TEXT NOT NULL DEFAULT '',
        content TEXT NOT NULL DEFAULT '',
        updated TEXT NOT NULL DEFAULT '',
        indexed_at TEXT NOT NULL DEFAULT (datetime('now'))
      );
    `);

    // Try FTS5 — fall back to substring if unavailable
    try {
      this.db.exec(`
        CREATE VIRTUAL TABLE IF NOT EXISTS files_fts USING fts5(
          path, title, content, tags,
          content='files', content_rowid='rowid'
        );

        CREATE TRIGGER IF NOT EXISTS files_ai AFTER INSERT ON files BEGIN
          INSERT INTO files_fts(rowid, path, title, content, tags)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_ad AFTER DELETE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_au AFTER UPDATE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);

[183 more lines in file. Use offset=56 to continue.]

          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_au AFTER UPDATE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
          INSERT INTO files_fts(rowid, path, title, content, tags)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags);
        END;
      `);
      this.hasFTS5 = true;
    } catch {
      this.hasFTS5 = false;
    }
  }

  // ─── File operations ──────────────────────────────────────────────

  upsertFile(file: IndexedFile): void {
    this.db.prepare(`
      INSERT INTO files (path, checksum, type, tags, title, content, updated, indexed_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, datetime('now'))
      ON CONFLICT(path) DO UPDATE SET
        checksum = excluded.checksum,
        type = excluded.type,
        tags = excluded.tags,
        title = excluded.title,
        content = excluded.content,
        updated = excluded.updated,
        indexed_at = datetime('now')
    `).run(
      file.path || "",
      file.checksum || "",
      file.type || "unknown",
      file.tags || "",
      file.title || "",
      file.content || "",
      file.updated || ""
    );
  }

  getFile(path: string): IndexedFile | undefined {
    return this.db.prepare("SELECT * FROM files WHERE path = ?").get(path) as IndexedFile | undefined;
  }

  deleteFile(path: string): boolean {
    const result = this.db.prepare("DELETE FROM files WHERE path = ?").run(path);
    return result.changes > 0;
  }

  listFiles(type?: string): IndexedFile[] {
    if (type) {
      return this.db.prepare("SELECT * FROM files WHERE type = ? ORDER BY updated DESC")
        .all(type) as IndexedFile[];
    }
    return this.db.prepare("SELECT * FROM files ORDER BY updated DESC").all() as IndexedFile[];
  }

  // ─── Search ────────────────────────────────────────────────────────

  search(query: string, limit = 10): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) return [];

    if (this.hasFTS5) {
      return this._searchFTS(query, limit);
    }
    return this._searchFallback(query, limit);
  }

  searchByType(query: string, type: string, limit = 10): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) {
      return this.listFiles(type).map(f => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score: 1,
      }));
    }

    if (this.hasFTS5) {
      return this._searchFTS(query, limit, type);
    }
    return this._searchFallback(query, limit, type);
  }

  searchByTag(tag: string, limit = 50): SearchResult[] {
    const files = this.db.prepare(
      "SELECT * FROM files WHERE tags LIKE ? ORDER BY updated DESC LIMIT ?"
    ).all(`%${tag}%`, limit) as IndexedFile[];

    return files.map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  private _searchFTS(query: string, limit: number, type?: string): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    const ftsQuery = terms.map(t => `"${t.replace(/"/g, '""')}"`).join(" OR ");

    let sql = `
      SELECT f.path, f.type, f.tags, f.title,
             substr(f.content, 1, 200) as excerpt,
             bm25(files_fts) as score
      FROM files f
      JOIN files_fts ft ON f.rowid = ft.rowid
      WHERE files_fts MATCH ?
    `;
    const params: unknown[] = [ftsQuery];

    if (type) {
      sql += " AND f.type = ?";
      params.push(type);
    }

    sql += " ORDER BY score LIMIT ?";
    params.push(limit);

    try {
      const rows = this.db.prepare(sql).all(...params) as Array<Record<string, unknown>>;
      return rows.map(r => ({
        file: r.path as string,
        type: r.type as string,
        tags: (r.tags as string) ? (r.tags as string).split(",").filter(Boolean) : [],
        title: r.title as string,
        excerpt: r.excerpt as string,
        score: r.score as number,
      }));
    } catch {
      return this._searchFallback(query, limit, type);
    }
  }

  private _searchFallback(query: string, limit: number, type?: string): SearchResult[] {
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    const files = type
      ? this.db.prepare("SELECT * FROM files WHERE type = ?").all(type) as IndexedFile[]
      : this.db.prepare("SELECT * FROM files").all() as IndexedFile[];

    return files
      .map(f => {
        const text = `${f.path} ${f.title} ${f.content} ${f.tags}`.toLowerCase();
        const matches = terms.filter(t => text.includes(t)).length;
        return { file: f, score: matches / terms.length };
      })
      .filter(({ score }) => score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(({ file: f, score }) => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score,
      }));
  }

  // ─── Stats ─────────────────────────────────────────────────────────

  stats(): { files: number; types: Record<string, number> } {
    const count = this.db.prepare("SELECT COUNT(*) as c FROM files").get() as { c: number };
    const typeRows = this.db.prepare(
      "SELECT type, COUNT(*) as c FROM files GROUP BY type"
    ).all() as Array<{ type: string; c: number }>;

    const types: Record<string, number> = {};
    for (const row of typeRows) {
      types[row.type] = row.c;
    }

    return { files: count.c, types };
  }

  // ─── Lifecycle ─────────────────────────────────────────────────────

  close(): void {
    this.db.close();
  }
}

