#!/usr/bin/env tsx
// recall.ts — Search the third-brain
// Usage: tsx scripts/recall.ts "what does Nik prefer for scripting"
//        tsx scripts/recall.ts --type person --tag nik
//        tsx scripts/recall.ts --limit 5 "job search"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import type { SearchResult } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RecallArgs {
  query: string;
  type?: string;
  tag?: string;
  limit: number;
}

function parseCliArgs(): RecallArgs {
  const { values, positionals } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string" },
      tag: { type: "string" },
      limit: { type: "string", default: "10" },
    },
    allowPositionals: true,
  });

  return {
    query: positionals.join(" ") || "",
    type: values.type as string | undefined,
    tag: values.tag as string | undefined,
    limit: parseInt(values.limit as string, 10) || 10,
  };
}

async function recall(args: RecallArgs): Promise<SearchResult[]> {
  const store = new BrainStore(DB_PATH);

  let results: SearchResult[];

  if (args.tag) {
    results = store.searchByTag(args.tag, args.limit);
  } else if (args.type && args.query) {
    results = store.searchByType(args.query, args.type, args.limit);
  } else if (args.type) {
    // List all of a type
    results = store.listFiles(args.type).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  } else if (args.query) {
    results = store.search(args.query, args.limit);
  } else {
    // No filter — list recent
    results = store.listFiles().slice(0, args.limit).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  store.close();
  return results;
}

function formatResults(results: SearchResult[]): string {
  if (results.length === 0) return "No memories found.";

  const lines: string[] = [];
  for (const r of results) {
    lines.push(`[${r.type}] ${r.title} (${r.file})`);
    lines.push(`  ${r.excerpt.replace(/\n/g, " ").slice(0, 150)}`);
    if (r.tags.length > 0) lines.push(`  tags: ${r.tags.join(", ")}`);
    lines.push("");
  }
  return lines.join("\n");
}

// Allow programmatic use
export async function recallMemory(
  query: string,
  options?: { type?: string; tag?: string; limit?: number }
): Promise<SearchResult[]> {
  return recall({
    query,
    type: options?.type,
    tag: options?.tag,
    limit: options?.limit || 10,
  });
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/recall.ts")) {
  const args = parseCliArgs();
  recall(args).then(results => {
    console.log(formatResults(results));
  }).catch(err => {
    console.error("recall failed:", err);
    process.exit(1);
  });
}

