function formatResults(results: SearchResult[], showDomain?: boolean): string {
  if (results.length === 0) return "No memories found.";

  const lines: string[] = [];
  for (const r of results) {
    lines.push(`[${r.type}] ${r.title} (${r.file})`);
    lines.push(`  ${r.excerpt.replace(/\n/g, " ").slice(0, 150)}`);
    if (r.tags.length > 0) lines.push(`  tags: ${r.tags.join(", ")}`);
    if (showDomain && (r as any).domain) lines.push(`  domain: ${(r as any).domain}`);
    lines.push("");
  }
  return lines.join("\n");
}

